#include "qp/data/dataset_writer.hpp"
#include "qp/schema/schema_version.hpp"
#include <fstream>
namespace qp::data {
static Result<std::ofstream> open_out(const std::filesystem::path& p){ auto parent=p.parent_path(); if(!parent.empty()) std::filesystem::create_directories(parent); std::ofstream out(p); if(!out) return Err<std::ofstream>(Error{ErrorCode::IoError,"failed to open output CSV",p.string()}); return Ok(std::move(out)); }
Result<void> write_bars_csv(const std::filesystem::path& path,const std::vector<OhlcvBar>& bars){ auto o=open_out(path); if(!o) return Err(o.error()); auto out=std::move(o).value(); out << "schema_version,symbol,start_ns,end_ns,open,high,low,close,volume\n"; for(const auto& b:bars){ auto ok=b.validate(); if(!ok) return ok; out << schema::dataset_bars_v1 << ',' << b.symbol.value << ',' << b.start.unix_nanos() << ',' << b.end.unix_nanos() << ',' << b.open.value << ',' << b.high.value << ',' << b.low.value << ',' << b.close.value << ',' << b.volume.value << "\n"; } return Ok(); }
Result<void> write_features_csv(const std::filesystem::path& path,const std::vector<features::FeatureValue>& rows){ auto o=open_out(path); if(!o) return Err(o.error()); auto out=std::move(o).value(); out << "schema_version,ts_ns,symbol,name,value\n"; for(const auto& r:rows){ auto ok=features::validate(r); if(!ok) return ok; out << schema::dataset_features_v1 << ',' << r.ts.unix_nanos() << ',' << r.symbol.value << ',' << r.name << ',' << r.value << "\n"; } return Ok(); }
Result<void> write_labels_csv(const std::filesystem::path& path,const std::vector<labels::LabelValue>& rows){ auto o=open_out(path); if(!o) return Err(o.error()); auto out=std::move(o).value(); out << "schema_version,sample_ts_ns,label_start_ns,label_end_ns,symbol,name,kind,value,leakage_safe\n"; for(const auto& r:rows){ auto ok=labels::validate(r); if(!ok) return ok; out << schema::dataset_labels_v1 << ',' << r.sample_ts.unix_nanos() << ',' << r.label_start_ts.unix_nanos() << ',' << r.label_end_ts.unix_nanos() << ',' << r.symbol.value << ',' << r.name << ',' << static_cast<int>(r.kind) << ',' << r.value << ',' << (r.leakage_safe?"true":"false") << "\n"; } return Ok(); }
Result<void> write_signals_csv(const std::filesystem::path& path,const std::vector<signals::Signal>& rows){ auto o=open_out(path); if(!o) return Err(o.error()); auto out=std::move(o).value(); out << "schema_version,ts_ns,symbol,name,side,strength\n"; for(const auto& r:rows){ auto ok=signals::validate(r); if(!ok) return ok; out << schema::dataset_signals_v1 << ',' << r.ts.unix_nanos() << ',' << r.symbol.value << ',' << r.name << ',' << static_cast<int>(r.side) << ',' << r.strength << "\n"; } return Ok(); }
}
